function normalizeKey(text) {
  return text.trim().toLowerCase().replace(/\s+/g, ' ');
}

function getAudioFile(wordId, ghegText) {
  if (ghegText) {
    const key = normalizeKey(ghegText);
    if (audioTextMap[key]) return audioTextMap[key];
    const stripped = key.replace(/[!.,?;:]+$/g, '');
    if (stripped !== key && audioTextMap[stripped]) return audioTextMap[stripped];
    for (const part of ghegText.split('/')) {
      const pk = normalizeKey(part);
      if (audioTextMap[pk]) return audioTextMap[pk];
      const ps = pk.replace(/[!.,?;:]+$/g, '');
      if (ps !== pk && audioTextMap[ps]) return audioTextMap[ps];
    }
  }
  return audioMap[wordId] || null;
}